import{_ as r,o,c as n,ag as s}from"./chunks/framework.WmBmIPw-.js";const m=JSON.parse('{"title":"遗传算法（Genetic Algorithm, GA）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/genetic-algorithm.md","filePath":"or-opt/genetic-algorithm.md","lastUpdated":1777119609000}'),a={name:"or-opt/genetic-algorithm.md"};function g(e,t,l,i,h,c){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="遗传算法-genetic-algorithm-ga" tabindex="-1">遗传算法（Genetic Algorithm, GA） <a class="header-anchor" href="#遗传算法-genetic-algorithm-ga" aria-label="Permalink to &quot;遗传算法（Genetic Algorithm, GA）&quot;">​</a></h1><p>遗传算法在<strong>有限规模种群</strong>上模拟「选择—交叉—变异」的循环：适者更易留下后代，<strong>交叉</strong>组合父代片段，<strong>变异</strong>引入小扰动。适合<strong>有良好编码</strong>与<strong>可快速评价适应度</strong>的问题，是群体类元启发式的代表。见 <a href="./metaheuristics.html">元启发式总览</a>。（更广义的<strong>进化计算</strong>还包含进化策略、遗传规划等，本页以经典 GA 为主干。）</p><p><strong>适用</strong>：组合或参数优化在能定义<strong>可行编码</strong>、<strong>适应度/目标 f</strong> 且邻域<strong>不宜</strong>用单点穷举时；规模很大时常与<strong>局部搜索、修复</strong>混合。</p><p><strong>核心</strong>：在一代代<strong>繁殖—替换</strong>中，以选择压推动目标改进、以交叉+变异在搜索空间<strong>扩散与补多样性</strong>；常保留<strong>历史最优</strong>（精英或外部存档）以免好解在随机操作中丢失。</p><hr><h2 id="算法-最小化示意" tabindex="-1">算法（最小化示意） <a class="header-anchor" href="#算法-最小化示意" aria-label="Permalink to &quot;算法（最小化示意）&quot;">​</a></h2><p>以最小化 f(s) 为例；s 在实现中为<strong>个体编码</strong>（二进制串、排列、实数向量等），适应度可<strong>直接取</strong> f(s) 或取单调变换（如 1 / (1+f)），<strong>评价规则</strong>在全程保持一致。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 遗传算法主循环（种群 + 选择 / 交叉 / 变异）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>在可行域上随机或启发式生成初始种群 P（个体数为 N），逐个评价 f。记当前种群里最优为 s⋆；设定：选择方式、交叉与变异算子、交叉率/变异率、代际替换策略、最大代数或评价次数、可选精英保留比例等。</p><h3 id="_2-一代迭代-重复直至终止条件" tabindex="-1">2. 一代迭代（重复直至终止条件） <a class="header-anchor" href="#_2-一代迭代-重复直至终止条件" aria-label="Permalink to &quot;2. 一代迭代（重复直至终止条件）&quot;">​</a></h3><ul><li><strong>亲本选择</strong>：由当前 P 中按选择规则选出一批用于繁殖的<strong>父本</strong>（可重复选同一好个体，依锦标赛、轮盘、排序等算子）。</li><li><strong>重组（交叉）</strong>：对父本两两或按算子<strong>配对</strong>，以<strong>交叉率</strong> p_c 在编码上执行交叉，得<strong>子代</strong>中间集。无交叉时子代可视为父本复制。</li><li><strong>变异</strong>：对子代个体以<strong>变异率</strong> p_m 执行变异（如比特翻、对换、高斯微扰等），<strong>保持或修复</strong>可行性。</li><li><strong>评价与替换</strong>：计算子代 f；按「完全替换、稳态（只换一部分）+ 精英」等策略<strong>组成</strong>下一代 P；若出现更优个体则更新 s⋆。</li></ul><h3 id="_3-终止" tabindex="-1">3. 终止 <a class="header-anchor" href="#_3-终止" aria-label="Permalink to &quot;3. 终止&quot;">​</a></h3><p>达到预设代数/时间/总适应度评价次数、或 s⋆ 长期不改进等，则停；输出 s⋆。</p></div><hr><h2 id="关键要素" tabindex="-1">关键要素 <a class="header-anchor" href="#关键要素" aria-label="Permalink to &quot;关键要素&quot;">​</a></h2><ul><li><strong>编码与可行性</strong>：TSP 常用<strong>排列</strong>；背包用<strong>0–1 串</strong>；实优化用<strong>实向量</strong>。非法个体需<strong>修复、惩罚</strong>或<strong>专用交叉变异</strong>保证可解。</li><li><strong>选择压</strong>：过强易早熟、种群趋同；过弱则收敛慢。常配合<strong>精英</strong>保留当前最优。</li><li><strong>交叉 / 变异</strong>：与编码强相关；<strong>PMX、OX</strong> 等用于排列，<strong>单点/多点交叉</strong> 用于二进串，<strong>算术交叉、SBX</strong> 等用于实数。</li><li><strong>参数</strong>：N、p_c、p_m 及终止条件多靠<strong>调参</strong>与多次运行。</li></ul><h2 id="与同类方法的差异-提要" tabindex="-1">与同类方法的差异（提要） <a class="header-anchor" href="#与同类方法的差异-提要" aria-label="Permalink to &quot;与同类方法的差异（提要）&quot;">​</a></h2><ul><li>相对<strong>单点</strong>方法（<a href="./simulated-annealing.html">模拟退火</a>、<a href="./tabu-search.html">禁忌搜索</a>）：<strong>并行</strong>维护多解、用<strong>种内重组</strong>在解空间<strong>跳跃</strong>，不必每步都定义邻域，但<strong>编码设计</strong>是成败关键。</li><li>常与<strong>局部搜索</strong>（Memetic）、<strong>多目标</strong>（NSGA-II 等）结合，本页不展开。</li></ul><h2 id="参考阅读" tabindex="-1">参考阅读 <a class="header-anchor" href="#参考阅读" aria-label="Permalink to &quot;参考阅读&quot;">​</a></h2><ul><li>Holland 的经典 GA 思想；Michalewicz 等关于<strong>实参编码与算子</strong>的著作；各应用领域教程中的「算子 + 调参 + 算例」可对照复现。</li><li>实现需把<strong>问题特定</strong>的<strong>编码、交叉、变异、修复</strong> 写进同一约定，便于重现实验与对比基线。</li></ul>',15)])])}const u=r(a,[["render",g]]);export{m as __pageData,u as default};
